import type { CustomerDto } from './models';
import type {
  CustomerBankAccountLine,
  CustomerDiscountTermLine,
} from './customerDetailModels';
import {
  mapBankLinesToPayload,
  mapDiscountLinesToPayload,
} from './customerDetailModels';

function supplierScalarPayload(form: Partial<CustomerDto>) {
  return {
    email: form.email?.trim() || null,
    contactPerson: form.contactPerson?.trim() || null,
    bankAccount: form.bankAccount?.trim() || null,
    bankName: form.bankName?.trim() || null,
    shortName: form.shortName?.trim() || null,
    paymentTermDays: form.paymentTermDays ?? 0,
    paymentMethod: form.paymentMethod?.trim() || null,
    accountingPhone: form.accountingPhone?.trim() || null,
    reconciliationEmail: form.reconciliationEmail?.trim() || null,
    salesContactName: form.salesContactName?.trim() || null,
    salesContactPhone: form.salesContactPhone?.trim() || null,
    notes: form.notes?.trim() || null,
    group1: form.group1?.trim() || null,
    group2: form.group2?.trim() || null,
    group3: form.group3?.trim() || null,
    gracePeriodDays: form.gracePeriodDays ?? 0,
    district: form.district?.trim() || null,
    province: form.province?.trim() || null,
    vatRegistered: form.vatRegistered ?? null,
    group4: form.group4?.trim() || null,
    creditLimit: form.creditLimit ?? 0,
  };
}

function gridPayload(
  bankLines?: CustomerBankAccountLine[],
  discountLines?: CustomerDiscountTermLine[],
) {
  return {
    bankAccounts: mapBankLinesToPayload(bankLines ?? []),
    discountTerms: mapDiscountLinesToPayload(discountLines ?? []),
  };
}

export function toCreateCustomerPayload(
  form: Partial<CustomerDto>,
  bankLines?: CustomerBankAccountLine[],
  discountLines?: CustomerDiscountTermLine[],
) {
  const code = form.code?.trim();
  return {
    ...(code ? { code } : {}),
    name: form.name,
    customerType: form.customerType,
    parentId: form.parentId?.trim() || null,
    customerGroupId: form.customerGroupId?.trim() || null,
    taxCode: form.taxCode,
    address: form.address,
    phone: form.phone,
    accountCode: form.accountCode?.trim() || null,
    isActive: form.isActive ?? true,
    ...supplierScalarPayload(form),
    ...gridPayload(bankLines, discountLines),
  };
}

export function toUpdateCustomerPayload(
  form: Partial<CustomerDto>,
  bankLines?: CustomerBankAccountLine[],
  discountLines?: CustomerDiscountTermLine[],
) {
  return {
    name: form.name,
    customerType: form.customerType,
    parentId: form.parentId?.trim() || null,
    customerGroupId: form.customerGroupId?.trim() || null,
    taxCode: form.taxCode,
    address: form.address,
    phone: form.phone,
    accountCode: form.accountCode?.trim() || null,
    isActive: form.isActive ?? true,
    ...supplierScalarPayload(form),
    ...gridPayload(bankLines, discountLines),
  };
}
