import { createSlice, PayloadAction } from '@reduxjs/toolkit';

interface ErpMasterState {
  loading: boolean;
}

const erpMasterSlice = createSlice({
  name: 'erpMaster',
  initialState: {
    loading: false,
  } as ErpMasterState,
  reducers: {
    setLoading(state, { payload }: PayloadAction<boolean>) {
      state.loading = payload;
    },
  },
});

export const { setLoading } = erpMasterSlice.actions;
export default erpMasterSlice.reducer;
