/** Detail grids — GET `/master/customers/:id` (CustomerDetailDto). */

export interface CustomerBankAccountLine {
  id?: string;
  accountKind: 'Company' | 'Sale' | string;
  bankName: string;
  accountNumber: string;
  branchName?: string;
  accountHolder?: string;
  isPrimary: boolean;
  sortOrder: number;
}

export interface CustomerDiscountTermLine {
  id?: string;
  supplierContractId?: string;
  contractNumber?: string;
  contractDate?: string;
  effectiveFrom?: string;
  effectiveTo?: string;
  discountPercent?: number;
  openingSupportPercent?: number;
  newProductSupportPercent?: number;
  birthdaySupportPercent?: number;
  shippingSupportPercent?: number;
  displaySupportPercent?: number;
  onTimePaymentBonusPercent?: number;
  salesBonusPercent?: number;
  note?: string;
  sortOrder: number;
}

export interface CustomerDetailDto {
  bankAccounts?: CustomerBankAccountLine[];
  discountTerms?: CustomerDiscountTermLine[];
}

const BANK_KIND_LABELS: Record<string, string> = {
  Company: 'Công ty',
  Sale: 'Sale',
};

export function customerBankKindLabel(kind?: string): string {
  if (!kind) return '';
  return BANK_KIND_LABELS[kind] ?? kind;
}

function pickRowVal(row: Record<string, unknown>, camel: string, pascal: string): unknown {
  return row[camel] ?? row[pascal];
}

export function mapBankLinesFromDto(
  rows?: Array<Record<string, unknown>>,
): CustomerBankAccountLine[] {
  if (!rows?.length) return [];
  return rows.map((r, idx) => ({
    id: pickRowVal(r, 'id', 'Id') != null ? String(pickRowVal(r, 'id', 'Id')) : undefined,
    accountKind: String(pickRowVal(r, 'accountKind', 'AccountKind') ?? 'Company'),
    bankName: String(pickRowVal(r, 'bankName', 'BankName') ?? ''),
    accountNumber: String(pickRowVal(r, 'accountNumber', 'AccountNumber') ?? ''),
    branchName: pickRowVal(r, 'branchName', 'BranchName') != null
      ? String(pickRowVal(r, 'branchName', 'BranchName'))
      : undefined,
    accountHolder: pickRowVal(r, 'accountHolder', 'AccountHolder') != null
      ? String(pickRowVal(r, 'accountHolder', 'AccountHolder'))
      : undefined,
    isPrimary: Boolean(pickRowVal(r, 'isPrimary', 'IsPrimary')),
    sortOrder: Number(pickRowVal(r, 'sortOrder', 'SortOrder') ?? idx),
  }));
}

export function mapDiscountLinesFromDto(
  rows?: Array<Record<string, unknown>>,
): CustomerDiscountTermLine[] {
  if (!rows?.length) return [];
  return rows.map((r, idx) => ({
    id: pickRowVal(r, 'id', 'Id') != null ? String(pickRowVal(r, 'id', 'Id')) : undefined,
    supplierContractId: pickRowVal(r, 'supplierContractId', 'SupplierContractId') != null
      ? String(pickRowVal(r, 'supplierContractId', 'SupplierContractId'))
      : undefined,
    contractNumber: pickRowVal(r, 'contractNumber', 'ContractNumber') != null
      ? String(pickRowVal(r, 'contractNumber', 'ContractNumber'))
      : undefined,
    contractDate: pickRowVal(r, 'contractDate', 'ContractDate') != null
      ? String(pickRowVal(r, 'contractDate', 'ContractDate'))
      : undefined,
    effectiveFrom: pickRowVal(r, 'effectiveFrom', 'EffectiveFrom') != null
      ? String(pickRowVal(r, 'effectiveFrom', 'EffectiveFrom'))
      : undefined,
    effectiveTo: pickRowVal(r, 'effectiveTo', 'EffectiveTo') != null
      ? String(pickRowVal(r, 'effectiveTo', 'EffectiveTo'))
      : undefined,
    discountPercent: pickRowVal(r, 'discountPercent', 'DiscountPercent') != null
      ? Number(pickRowVal(r, 'discountPercent', 'DiscountPercent'))
      : undefined,
    openingSupportPercent: pickRowVal(r, 'openingSupportPercent', 'OpeningSupportPercent') != null
      ? Number(pickRowVal(r, 'openingSupportPercent', 'OpeningSupportPercent'))
      : undefined,
    newProductSupportPercent: pickRowVal(r, 'newProductSupportPercent', 'NewProductSupportPercent') != null
      ? Number(pickRowVal(r, 'newProductSupportPercent', 'NewProductSupportPercent'))
      : undefined,
    birthdaySupportPercent: pickRowVal(r, 'birthdaySupportPercent', 'BirthdaySupportPercent') != null
      ? Number(pickRowVal(r, 'birthdaySupportPercent', 'BirthdaySupportPercent'))
      : undefined,
    shippingSupportPercent: pickRowVal(r, 'shippingSupportPercent', 'ShippingSupportPercent') != null
      ? Number(pickRowVal(r, 'shippingSupportPercent', 'ShippingSupportPercent'))
      : undefined,
    displaySupportPercent: pickRowVal(r, 'displaySupportPercent', 'DisplaySupportPercent') != null
      ? Number(pickRowVal(r, 'displaySupportPercent', 'DisplaySupportPercent'))
      : undefined,
    onTimePaymentBonusPercent: pickRowVal(r, 'onTimePaymentBonusPercent', 'OnTimePaymentBonusPercent') != null
      ? Number(pickRowVal(r, 'onTimePaymentBonusPercent', 'OnTimePaymentBonusPercent'))
      : undefined,
    salesBonusPercent: pickRowVal(r, 'salesBonusPercent', 'SalesBonusPercent') != null
      ? Number(pickRowVal(r, 'salesBonusPercent', 'SalesBonusPercent'))
      : undefined,
    note: pickRowVal(r, 'note', 'Note') != null ? String(pickRowVal(r, 'note', 'Note')) : undefined,
    sortOrder: Number(pickRowVal(r, 'sortOrder', 'SortOrder') ?? idx),
  }));
}

export function isSupplierLikeCustomerType(customerType?: string): boolean {
  const t = customerType?.trim() ?? '';
  return t === 'Supplier' || t === 'Both';
}

export function emptyBankAccountLine(sortOrder = 0): CustomerBankAccountLine {
  return {
    accountKind: 'Company',
    bankName: '',
    accountNumber: '',
    branchName: '',
    accountHolder: '',
    isPrimary: false,
    sortOrder,
  };
}

export function emptyDiscountTermLine(sortOrder = 0): CustomerDiscountTermLine {
  return {
    contractNumber: '',
    contractDate: '',
    effectiveFrom: '',
    effectiveTo: '',
    sortOrder,
  };
}

function toIsoDateOrNull(value?: string): string | null {
  const v = value?.trim();
  if (!v) return null;
  return v.length >= 10 ? v.slice(0, 10) : v;
}

function toPercentOrNull(value?: number): number | null {
  if (value == null || Number.isNaN(value)) return null;
  return value;
}

export function mapBankLinesToPayload(rows: CustomerBankAccountLine[]) {
  return rows
    .filter(r => r.bankName?.trim() || r.accountNumber?.trim())
    .map((r, idx) => ({
      id: r.id?.trim() || null,
      accountKind: r.accountKind?.trim() || 'Company',
      bankName: r.bankName?.trim() ?? '',
      accountNumber: r.accountNumber?.trim() ?? '',
      branchName: r.branchName?.trim() || null,
      accountHolder: r.accountHolder?.trim() || null,
      isPrimary: Boolean(r.isPrimary),
      sortOrder: r.sortOrder ?? idx,
    }));
}

export function mapDiscountLinesToPayload(rows: CustomerDiscountTermLine[]) {
  return rows
    .filter(r =>
      r.supplierContractId?.trim()
      || r.contractNumber?.trim()
      || r.contractDate?.trim()
      || r.effectiveFrom?.trim()
      || r.effectiveTo?.trim()
      || r.discountPercent != null
      || r.note?.trim(),
    )
    .map((r, idx) => ({
      id: r.id?.trim() || null,
      supplierContractId: r.supplierContractId?.trim() || null,
      contractNumber: r.contractNumber?.trim() || null,
      contractDate: toIsoDateOrNull(r.contractDate),
      effectiveFrom: toIsoDateOrNull(r.effectiveFrom),
      effectiveTo: toIsoDateOrNull(r.effectiveTo),
      discountPercent: toPercentOrNull(r.discountPercent),
      openingSupportPercent: toPercentOrNull(r.openingSupportPercent),
      newProductSupportPercent: toPercentOrNull(r.newProductSupportPercent),
      birthdaySupportPercent: toPercentOrNull(r.birthdaySupportPercent),
      shippingSupportPercent: toPercentOrNull(r.shippingSupportPercent),
      displaySupportPercent: toPercentOrNull(r.displaySupportPercent),
      onTimePaymentBonusPercent: toPercentOrNull(r.onTimePaymentBonusPercent),
      salesBonusPercent: toPercentOrNull(r.salesBonusPercent),
      note: r.note?.trim() || null,
      sortOrder: r.sortOrder ?? idx,
    }));
}
