import React from 'react';
import { Button } from '@linm-soft-org/linm-web-common-components';
import type { CodeReplacePending } from '../../services/master/codeReplace';
import styles from '../../styles/erpPage.module.css';

type CatalogFormCodeReplaceBannerProps = {
  testIdPrefix: string;
  pending?: CodeReplacePending;
  onViewDetail?: () => void;
};

export function CatalogFormCodeReplaceBanner({
  testIdPrefix,
  pending,
  onViewDetail,
}: CatalogFormCodeReplaceBannerProps): React.ReactElement | null {
  if (!pending) return null;
  const isFailed = pending.status === 'Failed';
  return (
    <div
      className={isFailed ? styles.catalogCodeReplaceBannerFailed : styles.catalogCodeReplaceBanner}
      data-testid={`${testIdPrefix}-code-replace-banner`}
    >
      <i className={`fas ${isFailed ? 'fa-times-circle' : 'fa-exchange-alt'}`} />
      <span>
        Đổi mã <strong>{pending.oldCode}</strong> → <strong>{pending.newCode}</strong>
        {' · '}
        {pending.status === 'Draft' && 'Chờ áp dụng'}
        {pending.status === 'Running' && 'Đang xử lý — lookup tạm khóa'}
        {pending.status === 'Failed' && (pending.errorMessage ?? 'Thất bại')}
        {pending.status === 'Completed' && 'Hoàn tất'}
      </span>
      {onViewDetail && pending.status === 'Draft' ? (
        <Button variant="secondary" size="sm" onClick={onViewDetail}>
          Xem preview
        </Button>
      ) : null}
    </div>
  );
}
