import type { SharedCatalogProposalSubmitChange } from '../components/catalog/SharedCatalogProposalModal';

/** Build BE payloadJson — flat fields + reason/note wrapper for change applier. */
export function buildSharedCatalogChangePayloadJson(
  submit: SharedCatalogProposalSubmitChange,
): string {
  const fields = submit.fields ?? {};
  return JSON.stringify({
    reason: submit.reason,
    note: submit.note,
    fields,
    name: fields.name,
    isActive: fields.isActive,
    isDetail: fields.isDetail,
    symbol: fields.symbol,
    location: fields.location,
    managerEmployeeCode: fields.managerEmployeeCode,
    unitCode: fields.unitCode,
    accountCode: fields.accountCode,
    taxCode: fields.taxCode,
    phone: fields.phone,
    debitAccountCode: fields.debitAccountCode,
    creditAccountCode: fields.creditAccountCode,
  });
}
